{"method":"tools/call","params":{"name":"create_file","arguments":{"file_path":"scripts/database/run-homepage-optimization.js","initial_content":"!U!SHALL!NOT!PARSE!/**\n * Homepage Performance Optimization Script\n * Menjalankan optimasi database untuk mempercepat homepage loading\n */\n\nconst { createClient } = require('@supabase/supabase-js');\nconst fs = require('fs');\nconst path = require('path');\n\n// Load environment variables\nrequire('dotenv').config({ path: '.env.local' });\n\nconst supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;\nconst supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;\n\nif (!supabaseUrl || !supabaseServiceKey) {\n  console.error('❌ Environment variables missing');\n  console.error('Required: NEXT_PUBLIC_SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY');\n  process.exit(1);\n}\n\nconst supabase = createClient(supabaseUrl, supabaseServiceKey);\n\nasync function runOptimization() {\n  console.log('🚀 STARTING HOMEPAGE OPTIMIZATION...');\n  console.log('');\n\n  try {\n    // 1. Check current database performance\n    console.log('📊 Checking current query performance...');\n    \n    const startTime = Date.now();\n    const { data: photos, error: photosError } = await supabase\n      .from('photos')\n      .select('id, url, thumbnail_url, original_name, optimized_images')\n      .eq('is_homepage', true)\n      .order('uploaded_at', { ascending: false })\n      .limit(20);\n    \n    const photosTime = Date.now() - startTime;\n    console.log(`   Photos query: ${photosTime}ms`);\n    \n    if (photosError) {\n      console.error('❌ Photos query error:', photosError);\n      return;\n    }\n\n    const startTimeEvents = Date.now();\n    const { data: events, error: eventsError } = await supabase\n      .from('events')\n      .select('id, name, date, is_premium, status')\n      .order('date', { ascending: false })\n      .limit(6);\n    \n    const eventsTime = Date.now() - startTimeEvents;\n    console.log(`   Events query: ${eventsTime}ms`);\n    \n    if (eventsError) {\n      console.error('❌ Events query error:', eventsError);\n      return;\n    }\n\n    console.log('');\n    console.log('📋 Current Performance:');\n    console.log(`   • Photos: ${photos?.length || 0} items in ${photosTime}ms`);\n    console.log(`   • Events: ${events?.length || 0} items in ${eventsTime}ms`);\n    console.log(`   • Total: ${photosTime + eventsTime}ms`);\n\n    // 2. Analyze optimized_images field\n    const optimizedCount = photos?.filter(p => p.optimized_images !== null).length || 0;\n    const totalPhotos = photos?.length || 0;\n    console.log(`   • Optimized images: ${optimizedCount}/${totalPhotos} (${Math.round(optimizedCount/totalPhotos*100)}%)`);\n\n    // 3. Performance recommendations\n    console.log('');\n    console.log('💡 OPTIMIZATION RECOMMENDATIONS:');\n    \n    if (photosTime > 500) {\n      console.log('🔴 CRITICAL: Photos query too slow (>500ms)');\n      console.log('   → Add database index: idx_photos_homepage_uploaded');\n      console.log('   → Consider reducing fields or limit');\n    }\n    \n    if (eventsTime > 300) {\n      console.log('🟡 HIGH: Events query slow (>300ms)');  \n      console.log('   → Add database index: idx_events_date_desc');\n    }\n\n    if (optimizedCount < totalPhotos * 0.5) {\n      console.log('🟡 MEDIUM: Many photos missing optimization');\n      console.log(`   → Process ${totalPhotos - optimizedCount} photos for optimization`);\n    }\n\n    // 4. Read and display migration SQL\n    console.log('');\n    console.log('📝 SUGGESTED DATABASE MIGRATION:');\n    console.log('');\n    \n    const migrationPath = path.join(__dirname, '../../supabase/migrations/20250913_optimize_homepage_performance.sql');\n    \n    if (fs.existsSync(migrationPath)) {\n      const migrationSQL = fs.readFileSync(migrationPath, 'utf8');\n      console.log('   Migration file created:', migrationPath);\n      console.log('');\n      console.log('   To apply this migration:');\n      console.log('   1. Copy the SQL to Supabase Dashboard → SQL Editor');\n      console.log('   2. Or use: npx supabase db push');\n      console.log('   3. Or apply manually via your preferred method');\n      console.log('');\n      console.log('🎯 Expected improvement: 70-80% faster queries');\n    } else {\n      console.log('❌ Migration file not found at:', migrationPath);\n    }\n\n  } catch (error) {\n    console.error('❌ Optimization failed:', error);\n  }\n}\n\n// Run the optimization\nrunOptimization();"}},"jsonrpc":"2.0","id":168}
